static void
display_augmentation_data (const unsigned char * data, const bfd_size_type len)
{
  bfd_size_type i;

  i = printf (_("  Augmentation data:    "));

  if (do_wide || len < ((80 - i) / 3))
    for (i = 0; i < len; ++i)
      printf (" %02x", data[i]);
  else
    {
      for (i = 0; i < len; ++i)
	{
	  if (i % (80 / 3) == 0)
	    putchar ('\n');
	  printf (" %02x", data[i]);
	}
    }
  putchar ('\n');
}

